#!/usr/bin/env node
// template-version: 1  (the skill compares this against its template to detect an outdated copy)
// PreToolUse context injector (matcher: Edit|Write|MultiEdit) - GENERATED by the
// project-code-style-analyzer skill; regenerate via the skill, do not hand-edit the
// extension list (it mirrors the languages the code-style-analyzer agents observed).
// On the FIRST code-file edit of a session it injects docs/PROJECT-CODE-STYLE.md into
// the model's context, then stays silent for the rest of the session (per-session dedup
// via a temp marker). This never blocks: it only adds context, always exit 0.
//   - Fires only for this project's own code extensions (below), so editing prose,
//     config, or the style doc itself never triggers it.
//   - Fail-soft everywhere: no doc, unparseable stdin, unwritable marker -> just proceed.
//   - The doc is the single source; re-running the skill refreshes it and (via the
//     mtime-keyed marker) the next edit re-injects the updated content.
const fs = require('fs');
const os = require('os');
const path = require('path');
const crypto = require('crypto');

const exit0 = () => process.exit(0);

let payload;
try {
  payload = JSON.parse(fs.readFileSync(0, 'utf8'));
} catch {
  exit0(); // unparseable stdin - never block
}

const input = (payload && payload.tool_input) || {};
const filePath = input.file_path || '';
// THIS PROJECT'S code extensions - the union the code-style-analyzer agents reported.
// __EXTENSIONS__ example: cs|xaml (WPF) - ts|html|scss (Angular) - cs (ASP.NET)
if (!/\.(__EXTENSIONS__)$/.test(filePath)) {
  exit0();
}

// Project root: PreToolUse stdin carries cwd; fall back to CLAUDE_PROJECT_DIR, then cwd.
const root = payload.cwd || process.env.CLAUDE_PROJECT_DIR || process.cwd();
const docPath = path.join(root, 'docs', 'PROJECT-CODE-STYLE.md');

let doc, stat;
try {
  stat = fs.statSync(docPath);
  doc = fs.readFileSync(docPath, 'utf8');
} catch {
  exit0(); // doc missing - nothing to inject
}
if (!doc.trim()) exit0();

// Per-session dedup, keyed on session + doc identity + mtime, so it injects once per session
// and re-injects if the doc is refreshed. Marker write failure falls through to injecting.
const key = crypto
  .createHash('sha1')
  .update(`${payload.session_id || ''}::${docPath}::${stat.mtimeMs}`)
  .digest('hex')
  .slice(0, 16);
const marker = path.join(os.tmpdir(), `claude-codestyle-${key}.marker`);
try {
  // wx = create-exclusive: succeeds once, throws EEXIST thereafter -> already injected this session.
  fs.writeFileSync(marker, '', { flag: 'wx' });
} catch (e) {
  if (e && e.code === 'EEXIST') exit0(); // already injected this session for this doc version
  // any other marker failure: proceed to inject (correctness over dedup)
}

// Keep the injection bounded - the doc is meant to be lean, but cap defensively.
const CAP = 16000;
let body = doc;
if (body.length > CAP) {
  body = body.slice(0, CAP) + `\n\n[...truncated - read the full ${'`docs/PROJECT-CODE-STYLE.md`'} for the rest.]`;
}

const context =
  `Project code style (docs/PROJECT-CODE-STYLE.md, maintained by the project-code-style-analyzer ` +
  `skill) - this is how THIS codebase actually writes code. Follow it for the code you are about ` +
  `to write; where it and a house convention differ, this project doc wins. Shown once this session:\n\n${body}`;

process.stdout.write(
  JSON.stringify({
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      additionalContext: context,
    },
  }),
);
process.exit(0);
